def missing_ids(ids, n):
    existing = set(ids)
    return [item_id for item_id in range(1, n + 1) if item_id not in existing]

def normalize_emails(emails):
    result = []
    for email in emails:
        normalized = email.strip().lower()
        if '@' in normalized:
