from datetime import datetime

def deduplicate_events(events):
    latest = {}
    for event in events:
        event_id = event['event_id']
        updated_at = datetime.fromisoformat(event['updated_at'])
        if event_id not in latest or updated_at > datetime.fromisoformat(latest[event_id]['updated_at']):
            latest[event_id] = event
    return list(latest.values())

def moving_average(values, window):
    if window <= 0:
        raise ValueError('window must be positive')
    result = []
    current_sum = 0
    for index, value in enumerate(values):
        current_sum += value
        if index >= window:
            current_sum -= values[index - window]
        if index >= window - 1:
            result.append(current_sum / window)
    return result

def merge_by_id(old_rows, new_rows):
    by_id = {row['id']: row for row in old_rows}
    for row in new_rows:
        by_id[row['id']] = row
    return list(by_id.values())

def detect_schema_drift(expected_columns, actual_columns):
    expected = set(expected_columns)
    actual = set(actual_columns)
    return {
        'missing': sorted(expected - actual),
        'extra': sorted(actual - expected),
    }

from collections import Counter

def find_duplicate_keys(rows, key):
    counts = Counter(row.get(key) for row in rows)
    return sorted(value for value, count in counts.items() if value is not None and count > 1)

